-bool ShenandoahBarrierC2Support::is_dominator(Node* d_c, Node* n_c, Node* d, Node* n, PhaseIdealLoop* phase) {
-  if (d_c != n_c) {
-    return phase->is_dominator(d_c, n_c);
-  }
-  return is_dominator_same_ctrl(d_c, d, n, phase);
