-    // Resolve object when orig-value is in cset.
-    // Make the unconditional resolve for fwdptr.
-
-    // Call lrb-stub and wire up that path in slots 4
-    Node* result_mem = nullptr;
-
-    Node* addr;
-    {
-      VectorSet visited;
