-              addr2->in(AddPNode::Base) == orig_base) {
-          addr2 = addr2->clone();
-          addr2->set_req(AddPNode::Base, base);
-          addr2->set_req(AddPNode::Address, base);
-          phase->register_new_node(addr2, ctrl);
