-MergeMemNode* MemoryGraphFixer::allocate_merge_mem(Node* mem, Node* rep_proj, Node* rep_ctrl) const {
-  MergeMemNode* mm = MergeMemNode::make(mem);
-  mm->set_memory_at(_alias, rep_proj);
