+#else
+    for(int i = int(n_bytes)-1;i >= 0;i--) {
+      append_byte(((const uint8_t*)src)[i]);
+    }
+#endif
+  }
+
+  void finalize() {
+    uint64_t nb = n_bits;
+
+    append_byte(0x80);
+
+    while(buffer_counter != 64 - 8) {
+      append_byte(0);
+    }
+
+    for(int i = 7;i >= 0;i--) {
+      uint8_t byte = (nb >> 8 * i) & 0xff;
+      append_byte(byte);
+    }
+  }
+
+  void finalize_bytes(void *dst_bytes32) {
+    uint8_t *ptr = (uint8_t*)dst_bytes32;
+    finalize();
+
+    for(int i = 0;i < 8;i++) {
+      for(int j = 3;j >= 0;j--) {
+        *ptr++ = (state[i] >> j * 8) & 0xff;
+      }
+    }
+  }
+};
