+#define TRANSPOSE_BLOCK(y2) do {                                        \
+    for(int x2=y2+1;x2<BS;x2++) {                                        \
+      element_t r = *(element_t *)&row[y2].r[x2*2+0];                        \
+      *(element_t *)&row[y2].r[x2*2+0] = *(element_t *)&row[x2].r[y2*2+0]; \
+      *(element_t *)&row[x2].r[y2*2+0] = r;                                \
+    }} while(0)
