+ALIGNED(8192) void tbut2f_%SHIFT%_%CONFIG%_%ISA%(real *RESTRICT out0, uint32_t *q, const real *RESTRICT in0, const real *RESTRICT tbl, const int K) {
+  const int shift = %SHIFT% + LOG2VECWIDTH, k = 1 << (shift - LOG2VECWIDTH);
+  int i=0;
+#pragma omp parallel for
+  for(i=0;i < k;i++) {
+    int i0 = i << LOG2VECWIDTH;
+    real *out = out0 + q[i];
+    const real *in = in0 + i0*2;
+    const int tbloffset = K * i0;
+
