+static bool check_d_d(const char *msg, vdouble (*vfunc)(vdouble), T (*tlfunc)(const T),
+                      const double *a0, size_t z, double tol, bool checkSignedZero) {
+  double s0[VECTLENDP];
+  for(size_t i=0;i<z;i++) {
+    memrand(s0, sizeof(s0));
+    int idx = xrand() & (VECTLENDP-1);
