+                           SLEEF_DBL_DENORM_MIN, DBL_MAX, checkSignedZero);
+    if (u > tol) {
+      printf("%s : arg = %a (%g), ulp = %g, t = %.16g, ", msg, a0[i], a0[i], u, s0[idx]);
+      cout << "c = " << tlfloat::to_string((*tlfunc)(a0[i])) << endl;
+      return false;
+    }
+  }
